#include <cstdlib>
#include <iostream>
#include <string>

// Stage scope: Basics (chapters 0-11). No vectors, classes, pointers,
// references, templates, lambdas, or <algorithm>. Pure functional style.

constexpr int kEasyMax{50};
constexpr int kMediumMax{100};
constexpr int kHardMax{500};

// Linear congruential generator. Deterministic across platforms so tests
// can pin exact targets. State is global to keep function signatures simple.
long g_rng_state{0};

void seedRng(int seed)
{
    g_rng_state = seed;
}

int nextRandom()
{
    g_rng_state = (g_rng_state * 1103515245L + 12345L) & 0x7fffffffL;
    return static_cast<int>(g_rng_state);
}

int rollTarget(int hi)
{
    return nextRandom() % hi + 1;
}

int maxForDifficulty(int difficulty)
{
    switch (difficulty)
    {
        case 1: return kEasyMax;
        case 2: return kMediumMax;
        case 3: return kHardMax;
        default: return kMediumMax;
    }
}

std::string nameForDifficulty(int difficulty)
{
    switch (difficulty)
    {
        case 1: return "easy";
        case 2: return "medium";
        case 3: return "hard";
        default: return "medium";
    }
}

// Read an integer from std::cin. If the user types something non-numeric,
// clear the fail bit, discard the bad line, and ask again. Calls std::exit
// on EOF so partial sessions terminate cleanly.
int readInt()
{
    int value{0};
    while (true)
    {
        if (std::cin >> value) return value;
        if (std::cin.eof()) std::exit(0);
        std::cin.clear();
        std::cin.ignore(10000, '\n');
        std::cout << "Please enter a whole number: ";
    }
}

// Overloaded prompts: with or without an explicit allowed range.
int promptInt(std::string label)
{
    std::cout << label;
    return readInt();
}

int promptInt(std::string label, int lo, int hi)
{
    while (true)
    {
        std::cout << label;
        const int value{readInt()};
        if (value >= lo && value <= hi) return value;
        std::cout << "Out of range. Pick between " << lo << " and " << hi << ".\n";
    }
}

int playRound(int difficulty)
{
    const int hi{maxForDifficulty(difficulty)};
    const int target{rollTarget(hi)};
    std::cout << "Difficulty " << nameForDifficulty(difficulty)
              << ": guess a number between 1 and " << hi << ".\n";

    int attempts{0};
    while (true)
    {
        ++attempts;
        const int guess{promptInt("Your guess: ", 1, hi)};
        if (guess == target)
        {
            std::cout << "Correct! You got it in " << attempts << " attempts.\n";
            return attempts;
        }
        if (guess < target)
            std::cout << "Too low.\n";
        else
            std::cout << "Too high.\n";
    }
}

int main()
{
    std::cout << "Welcome to Guess the Number!\n";

    const int seed{promptInt("Enter a seed: ")};
    seedRng(seed);

    int games{0};
    int totalAttempts{0};
    int bestAttempts{0};
    bool hasBest{false};

    while (true)
    {
        const int difficulty{promptInt("Choose difficulty (1=easy, 2=medium, 3=hard): ", 1, 3)};
        const int attempts{playRound(difficulty)};
        ++games;
        totalAttempts += attempts;
        if (!hasBest || attempts < bestAttempts)
        {
            bestAttempts = attempts;
            hasBest = true;
        }

        std::cout << "Play again? (y/n): ";
        char again{'n'};
        std::cin >> again;
        if (again != 'y' && again != 'Y') break;
    }

    std::cout << "\nFinal stats\n";
    std::cout << "Games played: " << games << "\n";
    std::cout << "Best round: " << bestAttempts << " attempts\n";
    const int avgTimes100{(totalAttempts * 100 + games / 2) / games};
    std::cout << "Average attempts: " << (avgTimes100 / 100) << "."
              << ((avgTimes100 / 10) % 10) << (avgTimes100 % 10) << "\n";
    std::cout << "Thanks for playing!\n";
    return 0;
}
